export enum AppState {
  IDLE = 'IDLE',
  CONNECTING = 'CONNECTING',
  IN_CALL = 'IN_CALL',
  ENDING = 'ENDING',
  ENDED = 'ENDED'
}

export enum SpeakerState {
  SILENT = 'SILENT',
  USER_SPEAKING = 'USER_SPEAKING',
  SYNERGY_SPEAKING = 'SYNERGY_SPEAKING'
}

export interface AudioVisualizerData {
  volume: number; // 0.0 to 1.0
  isSpeaking: boolean;
}

import { Blob } from '@google/genai';

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values to [-1, 1] before converting
    const s = Math.max(-1, Math.min(1, data[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: 'audio/pcm;rate=16000',
  };
}

// Simple RMS calculation for volume visualization
export function calculateRMS(data: Float32Array): number {
  let sum = 0;
  for (let i = 0; i < data.length; i++) {
    sum += data[i] * data[i];
  }
  return Math.sqrt(sum / data.length);
}

import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decodeAudioData, base64ToUint8Array, calculateRMS } from './audioUtils';
import { SpeakerState } from '../types';

interface LiveClientConfig {
  apiKey: string;
  onVolumeChange: (volume: number, speaker: SpeakerState) => void;
  onClose: () => void;
  onError: (error: any) => void;
}

export class LiveClient {
  private ai: GoogleGenAI;
  private config: LiveClientConfig;
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private inputSource: MediaStreamAudioSourceNode | null = null;
  private processor: ScriptProcessorNode | null = null;
  private stream: MediaStream | null = null;
  private nextStartTime = 0;
  private session: any = null;
  private isConnected = false;
  private userVolume = 0;
  private aiVolume = 0;
  private volumeInterval: number | null = null;

  constructor(config: LiveClientConfig) {
    this.config = config;
    this.ai = new GoogleGenAI({ apiKey: config.apiKey });
  }

  async connect() {
    if (this.isConnected) return;

    try {
      this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Request Microphone Access
      this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = this.ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log('Gemini Live Connection Opened');
            this.isConnected = true;
            this.startAudioInput(sessionPromise);
          },
          onmessage: (msg) => this.handleMessage(msg),
          onclose: (e) => {
            console.log('Gemini Live Connection Closed', e);
            this.disconnect();
            this.config.onClose();
          },
          onerror: (e) => {
            console.error('Gemini Live Connection Error', e);
            this.disconnect();
            this.config.onError(e);
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: "You are Synergy, a professional, calm, and efficient Front Desk Assistant for AV Tech AI Automation. Your voice is warm but precise. Keep responses concise and helpful. Do not use markdown. Do not describe your actions (like *nods*). Just speak naturally.",
        },
      });

      this.session = await sessionPromise;

      // Start volume monitoring loop
      this.startVolumeMonitoring();

    } catch (error) {
      console.error("Failed to connect:", error);
      this.disconnect();
      this.config.onError(error);
    }
  }

  private startAudioInput(sessionPromise: Promise<any>) {
    if (!this.inputAudioContext || !this.stream) return;

    this.inputSource = this.inputAudioContext.createMediaStreamSource(this.stream);
    this.processor = this.inputAudioContext.createScriptProcessor(4096, 1, 1);

    this.processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);

      // Calculate user volume for visualization
      const rms = calculateRMS(inputData);
      this.userVolume = rms; // Update raw volume, smoothed in UI

      const pcmBlob = createPcmBlob(inputData);

      sessionPromise.then((session) => {
          session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    this.inputSource.connect(this.processor);
    this.processor.connect(this.inputAudioContext.destination);
  }

  private async handleMessage(message: LiveServerMessage) {
    if (!this.outputAudioContext) return;

    const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

    if (base64Audio) {
      try {
        const audioBuffer = await decodeAudioData(
          base64ToUint8Array(base64Audio),
          this.outputAudioContext,
          24000,
          1
        );

        // Calculate AI volume from this chunk (approximate for the duration of this chunk)
        const channelData = audioBuffer.getChannelData(0);
        this.aiVolume = calculateRMS(channelData);

        this.playAudioBuffer(audioBuffer);
      } catch (e) {
        console.error("Error decoding audio", e);
      }
    }

    if (message.serverContent?.interrupted) {
      // Clear audio queue if interrupted
      this.outputAudioContext.suspend().then(() => this.outputAudioContext?.resume());
      this.nextStartTime = 0;
      this.aiVolume = 0;
    }
  }

  private playAudioBuffer(buffer: AudioBuffer) {
    if (!this.outputAudioContext) return;

    const source = this.outputAudioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(this.outputAudioContext.destination);

    const currentTime = this.outputAudioContext.currentTime;
    if (this.nextStartTime < currentTime) {
      this.nextStartTime = currentTime;
    }

    source.start(this.nextStartTime);

    // Reset volume when this chunk is done (roughly)
    source.onended = () => {
        // If no more chunks are queued close to now, drop volume
        if (Math.abs(this.outputAudioContext!.currentTime - this.nextStartTime) < 0.1) {
             this.aiVolume = 0;
        }
    };

    this.nextStartTime += buffer.duration;
  }

  private startVolumeMonitoring() {
    this.volumeInterval = window.setInterval(() => {
        // Determine who is speaking based on relative volume thresholds
        let speaker = SpeakerState.SILENT;
        let displayVolume = 0;

        // Simple gate
        const userThreshold = 0.01;
        const aiThreshold = 0.01;

        if (this.aiVolume > aiThreshold) {
            speaker = SpeakerState.SYNERGY_SPEAKING;
            displayVolume = Math.min(1, this.aiVolume * 5); // Boost for visual
        } else if (this.userVolume > userThreshold) {
            speaker = SpeakerState.USER_SPEAKING;
            displayVolume = Math.min(1, this.userVolume * 5);
        }

        this.config.onVolumeChange(displayVolume, speaker);
    }, 50);
  }

  disconnect() {
    this.isConnected = false;

    if (this.volumeInterval) {
        clearInterval(this.volumeInterval);
        this.volumeInterval = null;
    }

    if (this.session) {
      // session.close() is not explicitly available in provided types, 
      // but usually we just stop sending and close contexts.
      // If the SDK supports it: this.session.close();
      this.session = null;
    }

    if (this.inputSource) {
      this.inputSource.disconnect();
      this.inputSource = null;
    }
    if (this.processor) {
      this.processor.disconnect();
      this.processor = null;
    }
    if (this.stream) {
      this.stream.getTracks().forEach(track => track.stop());
      this.stream = null;
    }
    if (this.inputAudioContext) {
      this.inputAudioContext.close();
      this.inputAudioContext = null;
    }
    if (this.outputAudioContext) {
      this.outputAudioContext.close();
      this.outputAudioContext = null;
    }

    this.userVolume = 0;
    this.aiVolume = 0;
  }
}

import React, { useEffect, useState } from 'react';
import { AppState, SpeakerState } from '../types';

interface VoiceRingProps {
  appState: AppState;
  speakerState: SpeakerState;
  volume: number;
}

const VoiceRing: React.FC<VoiceRingProps> = ({ appState, speakerState, volume }) => {
  const [visualVolume, setVisualVolume] = useState(0.2); // Base size

  useEffect(() => {
    // Smooth the volume transition
    const targetScale = 0.2 + (volume * 0.8); // Scale between 0.2 (base) and 1.0
    setVisualVolume(prev => prev + (targetScale - prev) * 0.2);
  }, [volume]);

  // Dynamic Styles based on state
  const isIdle = appState === AppState.IDLE || appState === AppState.ENDED;
  const isConnecting = appState === AppState.CONNECTING;
  const isInCall = appState === AppState.IN_CALL;
  const isEnding = appState === AppState.ENDING;

  // Colors
  const synergyColor = 'rgb(34, 211, 238)'; // Cyan-400
  const userColor = 'rgb(255, 255, 255)';   // White
  const idleColor = 'rgba(34, 211, 238, 0.3)';

  let ringColor = synergyColor;
  let glowColor = 'rgba(6, 182, 212, 0.5)'; // Cyan-500 opacity

  if (isInCall) {
    if (speakerState === SpeakerState.USER_SPEAKING) {
        ringColor = userColor;
        glowColor = 'rgba(255, 255, 255, 0.4)';
    }
  } else if (isIdle || isEnding) {
    ringColor = idleColor;
    glowColor = 'rgba(6, 182, 212, 0.1)';
  }

  // Base sizing
  const baseSize = 200; // px

  // Calculate dynamic scale
  let scale = 1;
  if (isInCall) {
      scale = 1 + (visualVolume * 0.5); // Pulse up to 1.5x
  } else if (isConnecting) {
      scale = 1; // Animation handles it
  }

  return (
    <div className="relative flex items-center justify-center w-[400px] h-[400px]">
        {/* Connection Spinner */}
        {isConnecting && (
             <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-[220px] h-[220px] border-2 border-t-cyan-400 border-r-transparent border-b-cyan-900 border-l-transparent rounded-full animate-spin"></div>
             </div>
        )}

        {/* Outer Glow Ring (Breathing) */}
        <div 
            className={`absolute rounded-full transition-all duration-300 ease-out blur-xl`}
            style={{
                width: `${baseSize}px`,
                height: `${baseSize}px`,
                backgroundColor: glowColor,
                transform: `scale(${isIdle ? 1.1 : scale * 1.2})`,
                opacity: isIdle ? 0.5 : 0.8,
                animation: isIdle ? 'pulse 4s infinite' : 'none'
            }}
        />

        {/* Inner Solid Ring (The Core) */}
        <div 
            className={`absolute rounded-full border-2 transition-all duration-100 ease-linear flex items-center justify-center bg-black/50 backdrop-blur-sm`}
            style={{
                width: `${baseSize}px`,
                height: `${baseSize}px`,
                borderColor: ringColor,
                boxShadow: isInCall ? `0 0 ${visualVolume * 30}px ${ringColor}` : 'none',
                transform: `scale(${scale})`
            }}
        >
             {/* Core Dot */}
            <div 
                className={`w-2 h-2 rounded-full bg-cyan-400 transition-opacity duration-500 ${isIdle ? 'opacity-100' : 'opacity-0'}`}
            />
        </div>

        {/* Ripples for Active State */}
        {isInCall && (
             <>
                <div 
                    className="absolute border border-cyan-400/30 rounded-full"
                    style={{
                        width: `${baseSize}px`,
                        height: `${baseSize}px`,
                        transform: `scale(${scale * 1.1})`,
                        transition: 'transform 0.15s ease-out'
                    }}
                />
                 <div 
                    className="absolute border border-cyan-400/10 rounded-full"
                    style={{
                        width: `${baseSize}px`,
                        height: `${baseSize}px`,
                        transform: `scale(${scale * 1.3})`,
                        transition: 'transform 0.2s ease-out'
                    }}
                />
             </>
        )}
    </div>
  );
};

export default VoiceRing;

import React from 'react';
import { AppState } from '../types';

interface HeaderProps {
  appState: AppState;
  onEndCall: () => void;
}

const Header: React.FC<HeaderProps> = ({ appState, onEndCall }) => {
  const isInCall = appState === AppState.IN_CALL;

  return (
    <header className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-50">
      {/* Branding */}
      <div className="flex items-center gap-3">
        <div className="w-8 h-8 bg-gradient-to-tr from-cyan-600 to-cyan-400 rounded flex items-center justify-center text-white font-bold text-xs shadow-lg shadow-cyan-500/20">
            AV
        </div>
        <div className="flex flex-col">
            <span className="text-white font-semibold tracking-wide text-sm leading-tight">AV TECH</span>
            <span className="text-slate-400 text-[10px] tracking-wider uppercase">Automation</span>
        </div>
      </div>

      {/* Status & Action */}
      <div className="flex items-center gap-6">
        {isInCall && (
            <div className="flex items-center gap-2">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-green-400 text-xs font-medium tracking-wide">Call Connected</span>
