  );
};

export default Header;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Header from './components/Header';
import VoiceRing from './components/VoiceRing';
import { LiveClient } from './services/liveClient';
import { AppState, SpeakerState } from './types';

function App() {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [volume, setVolume] = useState(0);
  const [speakerState, setSpeakerState] = useState<SpeakerState>(SpeakerState.SILENT);

  // Ref to hold the client instance
  const liveClientRef = useRef<LiveClient | null>(null);

  const handleVolumeChange = useCallback((vol: number, speaker: SpeakerState) => {
    setVolume(vol);
    setSpeakerState(speaker);
  }, []);

  const handleError = useCallback((error: any) => {
    console.error("App Error:", error);
    // Graceful recovery to idle
    setAppState(AppState.IDLE);
    setSpeakerState(SpeakerState.SILENT);
    setVolume(0);
  }, []);

  const handleClose = useCallback(() => {
    if (appState !== AppState.ENDED) {
        setAppState(AppState.ENDED);
    }
  }, [appState]);

  const startCall = async () => {
    if (!process.env.API_KEY) {
      alert("API Key is missing. Please check configuration.");
      return;
    }

    setAppState(AppState.CONNECTING);

    const client = new LiveClient({
      apiKey: process.env.API_KEY,
      onVolumeChange: handleVolumeChange,
      onClose: handleClose,
      onError: handleError
    });

    liveClientRef.current = client;

    try {
      await client.connect();
      // Artificial delay for smooth transition if connection is too fast
      setTimeout(() => {
          setAppState(AppState.IN_CALL);
      }, 800);
    } catch (e) {
      handleError(e);
    }
  };

  const endCall = () => {
    setAppState(AppState.ENDING);
    if (liveClientRef.current) {
        liveClientRef.current.disconnect();
        liveClientRef.current = null;
    }

    // Aesthetic delay for the ending animation
    setTimeout(() => {
        setAppState(AppState.ENDED);
    }, 1500);
  };

  const resetToIdle = () => {
    setAppState(AppState.IDLE);
    setVolume(0);
    setSpeakerState(SpeakerState.SILENT);
  };

  // Main CTA Logic
  const renderMainButton = () => {
    if (appState === AppState.IDLE) {
        return (
            <button
                onClick={startCall}
                className="group relative px-8 py-4 bg-cyan-500 hover:bg-cyan-400 text-black font-bold rounded-full transition-all duration-300 shadow-[0_0_20px_rgba(6,182,212,0.4)] hover:shadow-[0_0_40px_rgba(6,182,212,0.6)] active:scale-95"
            >
                <span className="relative z-10 flex items-center gap-2">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                    </svg>
                    TALK TO SYNERGY
                </span>
            </button>
        );
    }

    if (appState === AppState.CONNECTING) {
        return (
            <button disabled className="px-8 py-4 bg-slate-800 text-slate-400 font-medium rounded-full cursor-wait flex items-center gap-3">
                <svg className="animate-spin h-5 w-5 text-cyan-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Connecting...
            </button>
        );
    }

    if (appState === AppState.IN_CALL) {
        // Button moves to header, so this area is empty or minimal status
        return (
            <div className="text-slate-500 text-sm animate-pulse tracking-widest uppercase">
                Listening
            </div>
        );
    }

    if (appState === AppState.ENDING) {
        return (
            <div className="text-slate-500 text-sm tracking-widest uppercase">
                Ending Session...
            </div>
        );
    }

    if (appState === AppState.ENDED) {
        return (
            <button
                onClick={resetToIdle} // In real app, might be window.location.href = '/'
                className="px-8 py-3 border border-slate-700 hover:border-cyan-500/50 hover:bg-slate-900 text-white rounded-full transition-all duration-300"
            >
                Return to Website
            </button>
        );
    }
  };

  return (
    <div className="h-screen w-full bg-gradient-to-b from-slate-900 to-black flex flex-col items-center relative overflow-hidden text-white font-sans selection:bg-cyan-500/30">

        {/* Background Ambient Glow */}
        <div className="absolute top-[-20%] left-[50%] -translate-x-1/2 w-[800px] h-[800px] bg-cyan-900/10 rounded-full blur-[120px] pointer-events-none" />

        <Header appState={appState} onEndCall={endCall} />

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col items-center justify-center w-full max-w-2xl relative z-10">

            <div className="mb-12 relative">
                <VoiceRing appState={appState} speakerState={speakerState} volume={volume} />
            </div>

            <div className={`text-center transition-all duration-500 ${appState === AppState.IN_CALL ? 'translate-y-8 scale-90 opacity-80' : ''}`}>
                <h1 className="text-3xl font-light tracking-tight text-white mb-2">Synergy</h1>
                <p className="text-cyan-400/80 text-sm font-medium tracking-wider uppercase">Front Desk Assistant</p>
            </div>

        </main>

        {/* Bottom Action Area */}
        <footer className="h-32 flex items-center justify-center w-full relative z-20">
            {renderMainButton()}
        </footer>
    </div>
  );
}

export default App;

import React, { useEffect, useState } from 'react';
import { AppState, SpeakerState } from '../types';

interface VoiceRingProps {
  appState: AppState;
  speakerState: SpeakerState;
  volume: number;
  size?: number;
}

const VoiceRing: React.FC<VoiceRingProps> = ({ appState, speakerState, volume, size = 200 }) => {
  const [visualVolume, setVisualVolume] = useState(0.2); // Base size

  useEffect(() => {
    // Smooth the volume transition
    const targetScale = 0.2 + (volume * 0.8); // Scale between 0.2 (base) and 1.0
    setVisualVolume(prev => prev + (targetScale - prev) * 0.2);
  }, [volume]);

  // Dynamic Styles based on state
  const isIdle = appState === AppState.IDLE || appState === AppState.ENDED;
  const isConnecting = appState === AppState.CONNECTING;
  const isInCall = appState === AppState.IN_CALL;
  const isEnding = appState === AppState.ENDING;

  // Colors
  const synergyColor = 'rgb(34, 211, 238)'; // Cyan-400
  const userColor = 'rgb(255, 255, 255)';   // White
  const idleColor = 'rgba(34, 211, 238, 0.3)';

  let ringColor = synergyColor;
  let glowColor = 'rgba(6, 182, 212, 0.5)'; // Cyan-500 opacity

  if (isInCall) {
    if (speakerState === SpeakerState.USER_SPEAKING) {
        ringColor = userColor;
        glowColor = 'rgba(255, 255, 255, 0.4)';
    }
  } else if (isIdle || isEnding) {
    ringColor = idleColor;
    glowColor = 'rgba(6, 182, 212, 0.1)';
  }

  // Base sizing
  const baseSize = size;

  // Calculate dynamic scale
  let scale = 1;
  if (isInCall) {
      scale = 1 + (visualVolume * 0.5); // Pulse up to 1.5x
  } else if (isConnecting) {
      scale = 1; // Animation handles it
  }

  // Container sizing should be larger than base size to accommodate ripples/glow
  const containerSize = size * 1.6;

  return (
    <div 
        className="relative flex items-center justify-center transition-all duration-500"
        style={{ width: containerSize, height: containerSize }}
    >
        {/* Connection Spinner */}
        {isConnecting && (
             <div className="absolute inset-0 flex items-center justify-center">
                 <div 
                    className="border-2 border-t-cyan-400 border-r-transparent border-b-cyan-900 border-l-transparent rounded-full animate-spin"
                    style={{ width: baseSize * 1.1, height: baseSize * 1.1 }}
                 ></div>
             </div>
        )}

        {/* Outer Glow Ring (Breathing) */}
        <div 
            className={`absolute rounded-full transition-all duration-300 ease-out blur-xl`}
            style={{
                width: `${baseSize}px`,
                height: `${baseSize}px`,
                backgroundColor: glowColor,
