function App() {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [volume, setVolume] = useState(0);
  const [speakerState, setSpeakerState] = useState<SpeakerState>(SpeakerState.SILENT);

  const liveClientRef = useRef<LiveClient | null>(null);

  const handleVolumeChange = useCallback((vol: number, speaker: SpeakerState) => {
    setVolume(vol);
    setSpeakerState(speaker);
  }, []);

  const handleError = useCallback((error: any) => {
    console.error("App Error:", error);
    setAppState(AppState.IDLE);
    setSpeakerState(SpeakerState.SILENT);
    setVolume(0);
  }, []);

  const handleClose = useCallback(() => {
    if (appState !== AppState.ENDED) {
        setAppState(AppState.ENDED);
    }
  }, [appState]);

  const startCall = async () => {
    if (!process.env.API_KEY) {
      alert("API Key is missing. Please check configuration.");
      return;
    }

    setAppState(AppState.CONNECTING);

    const client = new LiveClient({
      apiKey: process.env.API_KEY,
      onVolumeChange: handleVolumeChange,
      onClose: handleClose,
      onError: handleError
    });

    liveClientRef.current = client;

    try {
      await client.connect();
      setTimeout(() => {
          setAppState(AppState.IN_CALL);
      }, 1500); // Slightly longer delay for dramatic effect
    } catch (e) {
      handleError(e);
    }
  };

  const endCall = () => {
    setAppState(AppState.ENDING);
    if (liveClientRef.current) {
        liveClientRef.current.disconnect();
        liveClientRef.current = null;
    }
    setTimeout(() => {
        setAppState(AppState.ENDED);
        // Auto-reset to IDLE after ended for this specific flow to allow re-calls
        setTimeout(() => setAppState(AppState.IDLE), 2000); 
    }, 1500);
