  const liveClientRef = useRef<LiveClient | null>(null);

  const handleVolumeChange = useCallback((vol: number, speaker: SpeakerState) => {
    setVolume(vol);
    setSpeakerState(speaker);
  }, []);

  const handleError = useCallback((error: any) => {
    console.error("App Error:", error);
    setAppState(AppState.IDLE);
    setSpeakerState(SpeakerState.SILENT);
    setVolume(0);
  }, []);

  const handleClose = useCallback(() => {
    if (appState !== AppState.ENDED) {
        setAppState(AppState.ENDED);
    }
  }, [appState]);

  const startCall = async () => {
    if (!process.env.API_KEY) {
      alert("API Key is missing. Please check configuration.");
      return;
    }

    setAppState(AppState.CONNECTING);

    const client = new LiveClient({
      apiKey: process.env.API_KEY,
