import React, { useState, useCallback, useRef, useEffect } from 'react';
import Header from './components/Header';
import VoiceRing from './components/VoiceRing';
import { AppState, SpeakerState } from './types';

function App() {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [volume, setVolume] = useState(0);
  const [speakerState, setSpeakerState] = useState<SpeakerState>(SpeakerState.SILENT);

  const volumeIntervalRef = useRef<number | null>(null);

  const handleVolumeChange = useCallback((vol: number, speaker: SpeakerState) => {
    setVolume(vol);
    setSpeakerState(speaker);
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (volumeIntervalRef.current) {
        clearInterval(volumeIntervalRef.current);
      }
    };
  }, []);

  const startCall = () => {
    // MOCK BEHAVIOR - No API Key check, no real connection
    setAppState(AppState.CONNECTING);

    // Simulate connection delay (2 seconds)
    setTimeout(() => {
        setAppState(AppState.IN_CALL);

        // Start simulated voice activity
        if (volumeIntervalRef.current) clearInterval(volumeIntervalRef.current);
        volumeIntervalRef.current = window.setInterval(() => {
            // Random volume between 0 and 0.4
            const newVolume = Math.random() * 0.4;
            // Randomly switch speaker to simulate conversation
            const newSpeaker = Math.random() > 0.5 ? SpeakerState.SYNERGY_SPEAKING : SpeakerState.USER_SPEAKING;

            handleVolumeChange(newVolume, newSpeaker);
        }, 200);

    }, 2000);
  };

  const endCall = () => {
    setAppState(AppState.ENDING);

    // Stop simulated activity
    if (volumeIntervalRef.current) {
        clearInterval(volumeIntervalRef.current);
        volumeIntervalRef.current = null;
    }
    handleVolumeChange(0, SpeakerState.SILENT);

    // Transition to ENDED then IDLE
    setTimeout(() => {
        setAppState(AppState.ENDED);
        setTimeout(() => setAppState(AppState.IDLE), 2000); 
    }, 1500);
  };

  const isInteractive = appState === AppState.IDLE || appState === AppState.ENDED;
  const isConnecting = appState === AppState.CONNECTING;
  const isInCall = appState === AppState.IN_CALL;

  return (
    <div className="h-screen w-full bg-[#070707] flex flex-col relative overflow-hidden text-white font-sans selection:bg-purple-500/30">

        {/* Background Gradients */}
        <div className="absolute top-[-20%] left-0 w-[600px] h-[600px] bg-[#785ff9]/10 rounded-full blur-[120px] pointer-events-none" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] bg-purple-900/10 rounded-full blur-[100px] pointer-events-none" />

        <Header appState={appState} onEndCall={endCall} />

        {/* Main Content - Central Hero Container */}
        <main className="flex-1 flex items-center justify-center relative z-10 px-6 w-full">

            <div className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-24 items-center">

                {/* Left Column: Hero Text Group - CENTER ALIGNED */}
                <div className="flex flex-col items-center justify-center space-y-8 text-center">

                    {/* Front Desk Assistant Chip */}
                    <div className="inline-flex items-center px-4 py-1.5 rounded-full border border-[#785ff9]/30 bg-[#785ff9]/10 text-[#785ff9] text-[10px] font-bold tracking-widest uppercase shadow-[0_0_15px_rgba(120,95,249,0.15)]">
                        Built for Businesses Who Can’t Miss Calls
                    </div>

                    <h1 className="text-6xl md:text-8xl font-bold tracking-tight leading-[0.9]">
                        Never Miss a Call
                        <br />
                        <span className="text-slate-600">Never Miss a Lead</span>
                    </h1>

                    <p className="text-slate-400 text-lg md:text-xl font-light leading-relaxed max-w-lg">
                        AV Tech AI chat and voice agents handle conversations, qualify prospects, and book automatically while you’re offline.
                    </p>

                    {/* Identity Chips & Micro Text */}
                    <div className="flex flex-col gap-4 items-center">
                        <div className="flex flex-wrap gap-3 justify-center">
                            <div className="px-4 py-2 rounded-full border border-white/10 bg-white/5 backdrop-blur-sm flex items-center gap-2">
                                <div className="w-2 h-2 rounded-full bg-slate-400" />
                                <span className="text-xs font-medium text-slate-300 tracking-wide uppercase">See It In Action</span>
                            </div>
                            <div className="px-4 py-2 rounded-full border border-[#785ff9]/20 bg-[#785ff9]/5 backdrop-blur-sm flex items-center gap-2">
                                <div className="w-2 h-2 rounded-full bg-[#785ff9] animate-pulse" />
                                <span className="text-xs font-medium text-[#a78bfa] tracking-wide uppercase">Books jobs automatically</span>
                            </div>
                        </div>
                        <p className="text-slate-500 text-xs font-medium">
                            Live demos are limited each week to ensure quality setup.
                        </p>
                    </div>
                </div>

                {/* Right Column: Synergy Interaction Card */}
                <div className="flex items-center justify-center w-full relative scale-90">

                    {/* Card Container with subtle edge glow */}
                    <div 
                        className="w-full max-w-[36rem] bg-white/5 backdrop-blur-xl border border-white/10 rounded-[2.5rem] p-1 shadow-[0_0_40px_-10px_rgba(120,95,249,0.3)] overflow-hidden relative group transition-transform duration-500"
                    >

                        {/* Card Gloss Effect */}
                        <div className="absolute inset-0 bg-gradient-to-b from-white/5 to-transparent opacity-50 pointer-events-none" />

                        <div className="bg-[#0f121a]/80 rounded-[2.3rem] p-10 h-[625px] flex flex-col items-center justify-between relative transition-all duration-500">

                            {/* IDLE / CONNECTING STATE UI */}
                            {(isInteractive || isConnecting) && !isInCall && (
                                <>
                                    <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 w-full">

                                        {/* Phone Handset Icon - Scaled Up with Thicker Border */}
                                        <div className="w-32 h-32 rounded-full bg-slate-800/50 flex items-center justify-center mb-6 border-4 border-white/10 shadow-inner group-hover:border-[#785ff9]/30 transition-all duration-500">
                                            <svg className="w-14 h-14 text-[#785ff9]" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor">
                                                <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 6.75c0 8.284 6.716 15 15 15h2.25a2.25 2.25 0 002.25-2.25v-1.372c0-.516-.351-.966-.852-1.091l-4.423-1.106c-.44-.11-.902.055-1.173.417l-.97 1.293c-.282.376-.769.542-1.21.38a12.035 12.035 0 01-7.143-7.143c-.162-.441.004-.928.38-1.21l1.293-.97c.363-.271.527-.734.417-1.173L6.963 3.102a1.125 1.125 0 00-1.091-.852H4.5A2.25 2.25 0 002.25 4.5v2.25z" />
                                            </svg>
                                        </div>

                                        <div className="space-y-4">
                                            <h2 className="text-3xl font-semibold text-white tracking-tight">Meet Synergy</h2>
                                            <p className="text-slate-400 text-base leading-relaxed max-w-[300px] mx-auto">
                                                Our front desk assistant is ready to help you find a time on Arman's Calendar.
                                            </p>
                                        </div>
                                    </div>

                                    <button
                                        onClick={startCall}
                                        disabled={isConnecting}
                                        className={`w-[88%] py-5 rounded-full text-xl font-bold tracking-wide transition-colors duration-300 flex items-center justify-center gap-2 group
                                            ${isConnecting 
                                                ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                                                : 'bg-[#785ff9] hover:bg-[#8e7bf9] text-white'
                                            }`}
                                    >
                                        {isConnecting ? (
                                            <>
                                                <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                                </svg>
                                                CONNECTING
                                            </>
                                        ) : (
                                            <>
                                                Talk To Synergy
                                                <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                                                    <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                                                </svg>
                                            </>
                                        )}
                                    </button>
                                </>
                            )}

                            {/* IN-CALL STATE UI */}
                            {isInCall && (
                                <>
                                    <div className="w-full flex justify-between items-center absolute top-10 px-10">
                                        <div className="flex items-center gap-3">
                                            <span className="relative flex h-2.5 w-2.5">
                                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                                                <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-green-500"></span>
                                            </span>
                                            <span className="text-green-400 text-xs font-bold tracking-wider uppercase">Call Connected</span>
                                        </div>
                                        <div className="text-slate-500 text-xs font-mono">LIVE</div>
                                    </div>

                                    <div className="flex-1 flex flex-col items-center justify-center w-full mt-4">
                                        <VoiceRing appState={appState} speakerState={speakerState} volume={volume} size={180} />

                                        <div className="text-center mt-12 space-y-2">
                                            <h3 className="text-2xl font-medium text-white">Synergy</h3>
                                            <p className="text-[#785ff9]/80 text-xs font-bold tracking-widest uppercase">Front Desk Assistant</p>
                                        </div>
                                    </div>

                                    <button
                                        onClick={endCall}
                                        className="w-[88%] py-5 bg-[#785ff9] hover:bg-[#8e7bf9] text-white rounded-full font-bold tracking-wide transition-colors duration-200 mt-6"
                                    >
                                        END CALL
                                    </button>
                                </>
                            )}

                            {/* ENDING STATE */}
                            {appState === AppState.ENDING && (
                                <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 backdrop-blur-sm z-20 rounded-[2.3rem]">
                                    <p className="text-slate-400 tracking-widest text-sm uppercase animate-pulse">Ending Session...</p>
                                </div>
                            )}

                        </div>
                    </div>
                </div>

            </div>
        </main>

        {/* Footer */}
        <footer className="w-full border-t border-white/5 bg-[#070707] relative z-20">
            <div className="max-w-[1400px] mx-auto px-6 md:px-12 py-8 flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="opacity-50">
                    <span className="text-[10px] md:text-xs text-slate-500 font-medium tracking-widest uppercase">
                        © 2024 AV TECH AI AUTOMATION. ALL RIGHTS RESERVED.
                    </span>
                </div>

                <div className="flex gap-6 opacity-50">
                     <span className="text-[10px] md:text-xs text-slate-500 font-bold tracking-widest uppercase hover:text-slate-300 transition-colors cursor-pointer">
                        FAQ
                     </span>
                </div>
            </div>
        </footer>
    </div>
  );
}

